import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { FiEye, FiClock, FiCheckCircle, FiXCircle } from 'react-icons/fi';
import api from '../../services/api';

const MyOrders = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    fetchOrders();
  }, [filter]);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (filter) params.append('status', filter);
      params.append('limit', '50');
      const res = await api.get(`/orders/my-orders?${params.toString()}`);
      setOrders(res.data.orders);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    const badges = {
      pending: 'badge-warning',
      confirmed: 'badge-info',
      preparing: 'badge-info',
      ready: 'badge-success',
      served: 'badge-success',
      delivered: 'badge-success',
      cancelled: 'badge-danger'
    };
    return badges[status] || 'badge-info';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-dark-800 mb-8">My Orders</h1>

      <div className="flex gap-2 mb-6 flex-wrap">
        {['', 'pending', 'preparing', 'ready', 'served', 'cancelled'].map(status => (
          <button
            key={status}
            onClick={() => setFilter(status)}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              filter === status
                ? 'bg-primary-500 text-white'
                : 'bg-white text-dark-600 hover:bg-dark-50'
            }`}
          >
            {status || 'All'}
          </button>
        ))}
      </div>

      {orders.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-dark-500 text-lg mb-4">No orders found</p>
          <Link to="/menu" className="btn-primary">Order Now</Link>
        </div>
      ) : (
        <div className="space-y-4">
          {orders.map(order => (
            <div key={order._id} className="card p-6">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-semibold text-dark-800">#{order.orderNumber}</h3>
                    <span className={`badge ${getStatusBadge(order.status)}`}>{order.status}</span>
                  </div>
                  <p className="text-sm text-dark-500">
                    {new Date(order.createdAt).toLocaleDateString('en-US', {
                      year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
                    })}
                  </p>
                  <p className="text-sm text-dark-500 mt-1">
                    {order.items.length} items • ₹{order.totalAmount.toFixed(2)}
                  </p>
                </div>

                <div className="flex items-center gap-3">
                  <Link
                    to={`/track/${order.orderNumber}`}
                    className="btn-outline text-sm flex items-center gap-1"
                  >
                    <FiEye size={16} /> Track
                  </Link>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t">
                <div className="flex flex-wrap gap-2">
                  {order.items.map((item, idx) => (
                    <span key={idx} className="text-xs bg-dark-50 px-2 py-1 rounded-full text-dark-600">
                      {item.name} x{item.quantity}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MyOrders;
